import{_ as s,o as e,c as n,a2 as p}from"./chunks/framework.e-meDy3u.js";const u=JSON.parse('{"title":"Q4 · 后台没 API、只能导出 Excel，怎么办？","description":"","frontmatter":{},"headers":[],"relativePath":"q4.md","filePath":"q4.md"}'),t={name:"q4.md"};function l(r,a,o,i,c,d){return e(),n("div",null,[...a[0]||(a[0]=[p(`<h1 id="q4-·-后台没-api、只能导出-excel-怎么办" tabindex="-1">Q4 · 后台没 API、只能导出 Excel，怎么办？ <a class="header-anchor" href="#q4-·-后台没-api、只能导出-excel-怎么办" aria-label="Permalink to &quot;Q4 · 后台没 API、只能导出 Excel，怎么办？&quot;">​</a></h1><p class="hqq-lede">测的是心态，不是技术。撞到约束，第一反应是等接口，还是换条路？</p><h2 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h2><p><strong>没 API 照跑，这对第一版不是障碍。</strong></p><p>我要的不是实时数据流，是每天一次、口径固定、能对上账的回收数据进库。导出 Excel 就能满足，一行研发排期都不用等。</p><hr><h2 id="把两侧分清-取数在抖音侧-入库在飞书侧" tabindex="-1">把两侧分清：取数在抖音侧，入库在飞书侧 <a class="header-anchor" href="#把两侧分清-取数在抖音侧-入库在飞书侧" aria-label="Permalink to &quot;把两侧分清：取数在抖音侧，入库在飞书侧&quot;">​</a></h2><p><strong>取数（抖音侧）：</strong> 没有接口，现实入口就是人工导出 Excel。要自动化，路子不是等接口，是浏览器插件——跑在已登录的浏览器里，一键导出，不用资质、不用模拟登录。<strong>但第一版连插件都先不搭</strong>，就让人点一下导出。先把闭环跑通证明有用，再决定值不值得投自动化。</p><p><strong>入库（飞书侧）：</strong> 库建在飞书，飞书有全套 API 且立即可用，脚本把清洗好的数据批量写回表里，这一段稳、全自动。</p><hr><h2 id="七步-前三步是关键" tabindex="-1">七步，前三步是关键 <a class="header-anchor" href="#七步-前三步是关键" aria-label="Permalink to &quot;七步，前三步是关键&quot;">​</a></h2><p><strong>第一步：主键先定，用素材 ID，不用计划名。</strong></p><p>这是整件事的地基。千川报表里有创意/素材 ID，这是最稳的主键——一条素材可能挂在多个计划下，用计划名做键会漏掉素材维度的归并，而且批量托管的计划名未必让投手逐条自定义。主键落在素材 ID 上，计划名里的实验编号（格式定死，如 <code>HQ77-20260709-A1</code>）只作辅助校验。这一步在投放前约定好，命名对了后面全自动，命名乱了脚本也拼不回来。</p><p><strong>第二步：每天固定时间导出 Excel。</strong></p><p>谁导、几点导、导哪几张报表，写进 SOP。文件名按日期和平台命名，不靠人脑记。</p><p><strong>第三步：脚本清洗 Excel。</strong></p><p>统一列名、时间格式、字段口径。平台改一次导出格式，只改这一个清洗脚本，别处不动。</p><p><strong>第四步之后（全是脚本）：</strong></p><ul><li>用素材 ID 当主键，回写飞书表（走 API 批量写）</li><li>匹配失败进异常队列，绝不自动覆盖——宁可漏、不可脏</li><li>每次导入留原始文件 + 导入日志，随时能查</li></ul><p>整条链人只碰两个点：<strong>定命名（一次）、点导出（每天一下）</strong>。</p><hr><h2 id="取数自动化的路径-分级-按值不值得往上走" tabindex="-1">取数自动化的路径（分级，按值不值得往上走） <a class="header-anchor" href="#取数自动化的路径-分级-按值不值得往上走" aria-label="Permalink to &quot;取数自动化的路径（分级，按值不值得往上走）&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第一级：人点导出（第一版，稳定，免费）</span></span>
<span class="line"><span>   ↓ 导出频次高、手扛不住了</span></span>
<span class="line"><span>第二级：浏览器插件（Chrome extension）</span></span>
<span class="line"><span>         跑在已登录浏览器，不要资质，比无头 RPA 稳</span></span>
<span class="line"><span>   ↓ 插件覆盖不了的场景</span></span>
<span class="line"><span>第三级：无头 RPA（成本中，需维护）</span></span>
<span class="line"><span>   ↓ 业务真正做大，值得投</span></span>
<span class="line"><span>第四级：服务商资质 + 开放平台 API（最强，要资质审批周期）</span></span></code></pre></div><p>浏览器插件这条路我亲测过——飞书文档都能一键导成 markdown，千川后台导 Excel 同理。不是纸上谈兵。</p><hr><h2 id="诚实边界" tabindex="-1">诚实边界 <a class="header-anchor" href="#诚实边界" aria-label="Permalink to &quot;诚实边界&quot;">​</a></h2><p>没接口就没实时性。第一版是每天一次的节奏，不是实时大屏，这是硬约束。实时要等资质接口，我不吹这个第一周就能有。</p><p>命名规范是这套的命门，靠人执行。我会把它做进投放计划模板（能选就不手打）+ 每日入库前的命名合规校验（不合规当场退回投放的人改）+ 异常队列。用流程兜人性，不指望人自觉。</p><hr><details class="details custom-block"><summary>📱 微信简版 — 可直接发送</summary><p>第四题——后台没 API、只能导 Excel 怎么办。</p><p>没 API 我照跑，这对第一版不是障碍。我要的不是实时接口，是每天一次、能对上账的数据，导 Excel 就够。</p><p>关键不在工具，在我提前把素材 ID 和命名定死：人一次性焊进去，脚本就拿它当主键，把导出的 Excel 机械地拼回库里对应那条素材，对不上的进异常队列、绝不自动覆盖。人肉只剩&quot;点一下导出&quot;，一天几分钟。</p><p>这一下以后也能免掉——首选浏览器插件（跑在已登录的浏览器里、不用资质、比无头 RPA 稳，我亲测飞书文档都能一键导 markdown，千川导 Excel 同理）。但那是提速，不是前提，第一版一直手动导也稳稳跑。</p></details>`,30)])])}const g=s(t,[["render",l]]);export{u as __pageData,g as default};
